// src/components/pinsConfig.js

// Quick weather report types (emoji + label + color)
export const PIN_TYPES = {
  rain:   { label: "Raining here",           emoji: "🌧️", color: "#7aa2ff" },
  icy:    { label: "Roads are icy",          emoji: "🥶", color: "#7de3ff" },
  snow:   { label: "Snowing—be careful",     emoji: "❄️", color: "#c6e2ff" },
  flood:  { label: "Flooded area",           emoji: "🌊", color: "#4ac3ff" },
  wind:   { label: "High winds",             emoji: "💨", color: "#b9d6ff" },
  hail:   { label: "Hail reported",          emoji: "🧊", color: "#bfe9ff" },
  storm:  { label: "Thunderstorm",           emoji: "⛈️", color: "#9ab4ff" },
};
